using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments.OrderByDescending(s => s.ShippedDate)
            .Select(s => new ShipmentDto
            {
                Id = s.Id,
                TrackingNumber = s.TrackingNumber,
                Origin = s.Origin,
                Destination = s.Destination,
                Status = (ShipmentStatus)s.Status,
                ShippedDate = s.ShippedDate,
                EstimatedDelivery = s.EstimatedDelivery,
                CustomerEmail = s.CustomerEmail,
                Description = s.Description
            }).ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var s = await db.Shipments.FirstOrDefaultAsync(x => x.TrackingNumber == trackingNumber);
        if (s is null) return null;
        return new ShipmentDto
        {
            Id = s.Id,
            TrackingNumber = s.TrackingNumber,
            Origin = s.Origin,
            Destination = s.Destination,
            Status = (ShipmentStatus)s.Status,
            ShippedDate = s.ShippedDate,
            EstimatedDelivery = s.EstimatedDelivery,
            CustomerEmail = s.CustomerEmail,
            Description = s.Description
        };
    }

    public async Task<List<ShipmentDto>> GetShipmentsByCustomerAsync(string email)
    {
        return await db.Shipments.Where(s => s.CustomerEmail == email)
            .OrderByDescending(s => s.ShippedDate)
            .Select(s => new ShipmentDto
            {
                Id = s.Id,
                TrackingNumber = s.TrackingNumber,
                Origin = s.Origin,
                Destination = s.Destination,
                Status = (ShipmentStatus)s.Status,
                ShippedDate = s.ShippedDate,
                EstimatedDelivery = s.EstimatedDelivery,
                CustomerEmail = s.CustomerEmail,
                Description = s.Description
            }).ToListAsync();
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is not null)
        {
            shipment.Status = (int)status;
            await db.SaveChangesAsync();
        }
    }
}

