arguments.file_text:
@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Dispatch Dashboard</PageTitle>

<h2>📦 Shipment Dashboard</h2>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Filter by destination..."
           @bind="filterText" @bind:event="oninput" />
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Description</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>ETA</th>
                <th>Action</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td><strong>@s.TrackingNumber</strong></td>
                    <td>@s.Description</td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge @GetStatusBadge(s.Status)">@s.Status</span></td>
                    <td>@s.ShippedDate.ToString("MMM dd, yyyy")</td>
                    <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" value="@((int)s.Status)"
                                @onchange="(e) => UpdateStatus(s, e)">
                            @foreach (ShipmentStatus status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@((int)status)">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s => string.IsNullOrEmpty(filterText)
            || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)
            || s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var statusInt))
        {
            var newStatus = (ShipmentStatus)statusInt;
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>🔍 Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-100001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                @if (isSearching) { <span class="spinner-border spinner-border-sm"></span> }
                else { <span>Track</span> }
            </button>
        </div>
    </div>
</div>

@if (searchPerformed && shipment is null)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number "<em>@lastSearched</em>".
    </div>
}

@if (shipment is not null)
{
